/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Sends a JSON payload to the recipient URL. Uses a configurable transport
 * for HTTP delivery; defaults to an in-memory transport for testing.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationPayload,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * The JSON body POSTed to the webhook URL.
 */
export interface WebhookRequestBody {
  notificationId: string;
  type: string;
  subject: string;
  body: string;
  priority: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

/**
 * Transport interface for delivering webhook HTTP requests.
 * Implement this to integrate with a real HTTP client (fetch, axios, etc.).
 */
export interface WebhookTransport {
  post(url: string, body: WebhookRequestBody): Promise<{ statusCode: number }>;
}

/**
 * Configuration for the WebhookAdapter.
 */
export interface WebhookAdapterConfig {
  /** Optional custom transport. Defaults to in-memory transport. */
  transport?: WebhookTransport;
}

/**
 * In-memory transport for testing — stores posted webhooks instead of delivering them.
 */
export class InMemoryWebhookTransport implements WebhookTransport {
  private sent: Array<{ url: string; body: WebhookRequestBody; statusCode: number }> = [];
  private nextStatusCode = 200;

  async post(url: string, body: WebhookRequestBody): Promise<{ statusCode: number }> {
    const statusCode = this.nextStatusCode;
    this.sent.push({ url, body, statusCode });
    return { statusCode };
  }

  getSentWebhooks(): Array<{ url: string; body: WebhookRequestBody; statusCode: number }> {
    return [...this.sent];
  }

  setNextStatusCode(code: number): void {
    this.nextStatusCode = code;
  }

  clear(): void {
    this.sent = [];
    this.nextStatusCode = 200;
  }
}

/**
 * Validate that a string looks like a plausible webhook URL.
 */
function isValidUrl(url: string): boolean {
  return /^https?:\/\/[^\s]+$/.test(url);
}

export class WebhookAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private transport: WebhookTransport;
  private sentWebhooks: NotificationPayload[] = [];

  constructor(config?: WebhookAdapterConfig) {
    this.transport = config?.transport ?? new InMemoryWebhookTransport();
  }

  /**
   * Send a webhook notification.
   *
   * Validates the recipient URL, formats the payload as JSON, and POSTs it.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending webhook to ${payload.recipient}: ${payload.subject}`);

    // Validate recipient URL
    const url = this.resolveRecipient(payload.recipient);
    if (!url) {
      const error = `Invalid webhook URL: ${payload.recipient}`;
      this.logger.error(error);
      return {
        notificationId: payload.id,
        channel: this.channel,
        success: false,
        error,
        deliveredAt: new Date(),
      };
    }

    // Format the webhook request body
    const body = this.formatPayload(payload);

    try {
      const result = await this.transport.post(url, body);

      if (result.statusCode >= 200 && result.statusCode < 300) {
        this.logger.info(`Webhook delivered to ${url} (status ${result.statusCode})`);
        this.sentWebhooks.push(payload);

        return {
          notificationId: payload.id,
          channel: this.channel,
          success: true,
          deliveredAt: new Date(),
        };
      } else {
        const error = `Webhook returned status ${result.statusCode}`;
        this.logger.error(`Webhook delivery failed for ${payload.id}: ${error}`);
        return {
          notificationId: payload.id,
          channel: this.channel,
          success: false,
          error,
          deliveredAt: new Date(),
        };
      }
    } catch (err) {
      const error = err instanceof Error ? err.message : 'Unknown transport error';
      this.logger.error(`Webhook delivery failed for ${payload.id}: ${error}`);
      return {
        notificationId: payload.id,
        channel: this.channel,
        success: false,
        error,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Resolve and validate the recipient webhook URL.
   * Returns the validated URL or null if invalid.
   */
  resolveRecipient(recipient: string): string | null {
    const trimmed = recipient.trim();
    if (!isValidUrl(trimmed)) {
      return null;
    }
    return trimmed;
  }

  /**
   * Format the notification payload as a webhook request body.
   */
  formatPayload(payload: NotificationPayload): WebhookRequestBody {
    return {
      notificationId: payload.id,
      type: payload.type,
      subject: payload.subject,
      body: payload.body,
      priority: payload.priority,
      createdAt: payload.createdAt.toISOString(),
      ...(payload.metadata ? { metadata: payload.metadata } : {}),
    };
  }

  /**
   * Get all successfully sent webhooks (useful for testing).
   */
  getSentWebhooks(): NotificationPayload[] {
    return [...this.sentWebhooks];
  }

  /**
   * Clear sent webhook history (useful for testing).
   */
  clearSentWebhooks(): void {
    this.sentWebhooks = [];
  }

  /**
   * Get the underlying transport (useful for testing with InMemoryWebhookTransport).
   */
  getTransport(): WebhookTransport {
    return this.transport;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  WebhookAdapter,
  InMemoryWebhookTransport,
  type WebhookTransport,
} from '../../src/adapters/webhook.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function createPayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order:confirmation',
    channel: 'webhook',
    recipient: 'https://example.com/webhook',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-01-15T12:00:00Z'),
    ...overrides,
  };
}

describe('WebhookAdapter', () => {
  let adapter: WebhookAdapter;
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookAdapter({ transport });
  });

  describe('send', () => {
    it('should deliver a webhook through the transport', async () => {
      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');

      const sent = transport.getSentWebhooks();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.url).toBe('https://example.com/webhook');
      expect(sent[0]?.body.notificationId).toBe('notif-0001');
    });

    it('should format the payload as JSON', async () => {
      const payload = createPayload();
      await adapter.send(payload);

      const sent = transport.getSentWebhooks();
      const body = sent[0]?.body;
      expect(body).toEqual({
        notificationId: 'notif-0001',
        type: 'order:confirmation',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
        priority: 'normal',
        createdAt: '2026-01-15T12:00:00.000Z',
      });
    });

    it('should include metadata when present', async () => {
      const payload = createPayload({ metadata: { orderId: 'order-1' } });
      await adapter.send(payload);

      const sent = transport.getSentWebhooks();
      expect(sent[0]?.body.metadata).toEqual({ orderId: 'order-1' });
    });

    it('should not include metadata key when absent', async () => {
      const payload = createPayload();
      await adapter.send(payload);

      const sent = transport.getSentWebhooks();
      expect(sent[0]?.body).not.toHaveProperty('metadata');
    });

    it('should track sent webhooks', async () => {
      await adapter.send(createPayload());
      await adapter.send(createPayload({ id: 'notif-0002', recipient: 'https://other.com/hook' }));

      expect(adapter.getSentWebhooks()).toHaveLength(2);
    });

    it('should clear sent webhooks', async () => {
      await adapter.send(createPayload());
      adapter.clearSentWebhooks();

      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should fail for invalid recipient URL', async () => {
      const payload = createPayload({ recipient: 'not-a-url' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(transport.getSentWebhooks()).toHaveLength(0);
    });

    it('should fail for empty recipient', async () => {
      const payload = createPayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
    });

    it('should fail for non-HTTP URL', async () => {
      const payload = createPayload({ recipient: 'ftp://example.com/hook' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
    });

    it('should fail when transport returns non-2xx status', async () => {
      transport.setNextStatusCode(500);

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('status 500');
      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should fail when transport returns 404', async () => {
      transport.setNextStatusCode(404);

      const payload = createPayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('status 404');
    });

    it('should handle transport errors gracefully', async () => {
      const failingTransport: WebhookTransport = {
        post: async () => {
          throw new Error('Connection refused');
        },
      };

      adapter = new WebhookAdapter({ transport: failingTransport });
      const result = await adapter.send(createPayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
      expect(adapter.getSentWebhooks()).toHaveLength(0);
    });

    it('should handle non-Error transport throws', async () => {
      const failingTransport: WebhookTransport = {
        post: async () => {
          throw 'string error';
        },
      };

      adapter = new WebhookAdapter({ transport: failingTransport });
      const result = await adapter.send(createPayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Unknown transport error');
    });
  });

  describe('resolveRecipient', () => {
    it('should accept valid HTTPS URLs', () => {
      expect(adapter.resolveRecipient('https://example.com/webhook')).toBe('https://example.com/webhook');
    });

    it('should accept valid HTTP URLs', () => {
      expect(adapter.resolveRecipient('http://localhost:3000/hook')).toBe('http://localhost:3000/hook');
    });

    it('should trim whitespace', () => {
      expect(adapter.resolveRecipient('  https://example.com/hook  ')).toBe('https://example.com/hook');
    });

    it('should return null for invalid URLs', () => {
      expect(adapter.resolveRecipient('not-a-url')).toBeNull();
      expect(adapter.resolveRecipient('ftp://example.com')).toBeNull();
      expect(adapter.resolveRecipient('')).toBeNull();
    });
  });

  describe('formatPayload', () => {
    it('should format notification payload as webhook request body', () => {
      const payload = createPayload();
      const body = adapter.formatPayload(payload);

      expect(body.notificationId).toBe('notif-0001');
      expect(body.type).toBe('order:confirmation');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toContain('Widget x2');
      expect(body.priority).toBe('normal');
      expect(body.createdAt).toBe('2026-01-15T12:00:00.000Z');
    });

    it('should include metadata when present', () => {
      const payload = createPayload({ metadata: { key: 'value' } });
      const body = adapter.formatPayload(payload);

      expect(body.metadata).toEqual({ key: 'value' });
    });
  });

  describe('InMemoryWebhookTransport', () => {
    it('should store and retrieve sent webhooks', async () => {
      const t = new InMemoryWebhookTransport();
      await t.post('https://example.com/hook', {
        notificationId: 'n1',
        type: 'order:confirmation',
        subject: 'Test',
        body: 'Body',
        priority: 'normal',
        createdAt: '2026-01-15T12:00:00.000Z',
      });

      expect(t.getSentWebhooks()).toHaveLength(1);
      expect(t.getSentWebhooks()[0]?.url).toBe('https://example.com/hook');
    });

    it('should return configured status code', async () => {
      const t = new InMemoryWebhookTransport();
      t.setNextStatusCode(503);

      const result = await t.post('https://example.com/hook', {
        notificationId: 'n1',
        type: 'order:confirmation',
        subject: 'Test',
        body: 'Body',
        priority: 'normal',
        createdAt: '2026-01-15T12:00:00.000Z',
      });

      expect(result.statusCode).toBe(503);
    });

    it('should clear sent webhooks and reset status code', async () => {
      const t = new InMemoryWebhookTransport();
      t.setNextStatusCode(500);
      await t.post('https://example.com/hook', {
        notificationId: 'n1',
        type: 'order:confirmation',
        subject: 'Test',
        body: 'Body',
        priority: 'normal',
        createdAt: '2026-01-15T12:00:00.000Z',
      });

      t.clear();
      expect(t.getSentWebhooks()).toHaveLength(0);

      const result = await t.post('https://example.com/hook', {
        notificationId: 'n2',
        type: 'order:confirmation',
        subject: 'Test',
        body: 'Body',
        priority: 'normal',
        createdAt: '2026-01-15T12:00:00.000Z',
      });
      expect(result.statusCode).toBe(200);
    });
  });
});

